import{_ as c,C as r,o,c as i,a3 as t,b as n,w as a,a as s,E as d,a4 as p}from"./chunks/framework.aYYe0dfI.js";const v=JSON.parse('{"title":"Module client","description":"The client module provides the public-facing asynchronous interface for interacting with large language model (LLM) endpoints. It exposes three primary templated functions: call_llm_async, call_completion_async, and call_structured_async. These functions accept model identifiers, prompts, and optional event loop pointers, returning integer handles or status codes. The module internally manages event loop selection through clore::net::detail::select_event_loop, ensuring asynchronous operations are dispatched on a valid kota::event_loop. The public scope also includes variables for request construction, such as system_prompt, model, prompt, and tool-related flags, enabling callers to configure and track LLM calls without directly handling low-level networking.","frontmatter":{"title":"Module client","description":"The client module provides the public-facing asynchronous interface for interacting with large language model (LLM) endpoints. It exposes three primary templated functions: call_llm_async, call_completion_async, and call_structured_async. These functions accept model identifiers, prompts, and optional event loop pointers, returning integer handles or status codes. The module internally manages event loop selection through clore::net::detail::select_event_loop, ensuring asynchronous operations are dispatched on a valid kota::event_loop. The public scope also includes variables for request construction, such as system_prompt, model, prompt, and tool-related flags, enabling callers to configure and track LLM calls without directly handling low-level networking.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/client/index.md","filePath":"en/clore/modules/client/index.md"}'),h={name:"clore/modules/client/index.md"};function u(m,e,f,g,_,b){const l=r("Mermaid");return o(),i("div",null,[e[1]||(e[1]=t('<h1 id="module-client" tabindex="-1">Module <code>client</code> <a class="header-anchor" href="#module-client" aria-label="Permalink to &quot;Module `client`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>client</code> module provides the public-facing asynchronous interface for interacting with large language model (LLM) endpoints. It exposes three primary templated functions: <code>call_llm_async</code>, <code>call_completion_async</code>, and <code>call_structured_async</code>. These functions accept model identifiers, prompts, and optional event loop pointers, returning integer handles or status codes. The module internally manages event loop selection through <code>clore::net::detail::select_event_loop</code>, ensuring asynchronous operations are dispatched on a valid <code>kota::event_loop</code>. The public scope also includes variables for request construction, such as <code>system_prompt</code>, <code>model</code>, <code>prompt</code>, and tool-related flags, enabling callers to configure and track LLM calls without directly handling low-level networking.</p><p>The module builds upon the <code>http</code>, <code>protocol</code>, <code>schema</code>, and <code>support</code> modules, leveraging their capabilities for HTTP dispatch, request/response data structures, structured output schemas, and logging utilities. Its responsibility centers on orchestrating the complete lifecycle of an LLM request—from parameter assembly and event loop binding to response handling—while abstracting protocol-specific details behind the <code>Protocol</code> template parameter. This design allows callers to focus on application logic while the module ensures reliable asynchronous execution and integration with the broader <code>clore</code> networking layer.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../http/"><code>http</code></a></li><li><a href="./../protocol/"><code>protocol</code></a></li><li><a href="./../schema/"><code>schema</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../anthropic/"><code>anthropic</code></a></li><li><a href="./../openai/"><code>openai</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',9)),(o(),n(p,null,{default:a(()=>[d(l,{id:"mermaid-60",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22client%22%5D%0A%20%20%20%20I0%5B%22http%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22protocol%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22schema%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A%20%20%20%20I3%5B%22support%22%5D%0A%20%20%20%20I3%20--%3E%20M0%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-call-completion-async" tabindex="-1"><code>clore::net::call_completion_async</code> <a class="header-anchor" href="#clore-net-call-completion-async" aria-label="Permalink to &quot;`clore::net::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:16</code></p><p>Definition: <code>network/client.cppm:57</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>The implementation of <code>clore::net::call_completion_async</code> employs a capability-probing retry loop (up to four attempts) to gracefully handle provider limitations exposed via HTTP 4xx rejection errors. On each iteration, the request is first sanitized against the current probed capabilities via <code>sanitize_request_for_capabilities</code>. The <code>Protocol</code>‑specific methods <code>build_request_json</code>, <code>read_environment</code>, <code>build_url</code>, and <code>build_headers</code> are then called to construct the outgoing payload and endpoint details. An asynchronous HTTP request is dispatched using <code>clore::net::detail::perform_http_request_async</code> on the event loop returned by <code>clore::net::detail::select_event_loop</code>. If the response carries a 4xx status and the body indicates a feature rejection (e.g., <code>response_format</code>, <code>tool_choice</code>, <code>parallel_tool_calls</code>, or <code>tools</code>), the corresponding capability flag in <code>caps</code> is updated to <code>false</code>, and the loop continues with the sanitized request as the new input. If the sanitization stripped tools while the original request required them, the function immediately fails with an <code>LLMError</code>. Otherwise, the raw response is parsed via <code>Protocol::parse_response</code> and the parsed result is returned. If all probing attempts are exhausted without success, the coroutine fails with an exhaustion error.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>mutates global capabilities cache via atomic stores</li><li>performs HTTP I/O</li><li>logs warnings via <code>logging::warn</code></li><li>may fail <code>co_await</code> with <code>LLMError</code></li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>CompletionRequest request</code></li><li>global capabilities cache from <code>get_probed_capabilities</code></li><li>environment variables via <code>Protocol::read_environment</code></li><li>HTTP response body</li><li>event loop reference</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>capabilities cache atomic booleans (<code>supports_json_schema</code>, <code>supports_tool_choice</code>, <code>supports_parallel_tool_calls</code>, <code>supports_tools</code>)</li><li>output task result (either <code>CompletionResponse</code> or <code>LLMError</code>)</li><li>log output</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>retry loop with capability probing</li><li>used by higher-level completion functions</li><li>handles feature rejection errors</li></ul><h3 id="clore-net-call-llm-async" tabindex="-1"><code>clore::net::call_llm_async</code> <a class="header-anchor" href="#clore-net-call-llm-async" aria-label="Permalink to &quot;`clore::net::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:20</code></p><p>Definition: <code>network/client.cppm:137</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>The implementation of <code>clore::net::call_llm_async</code> is a coroutine that first resolves the active event loop via <code>detail::select_event_loop</code>, falling back to the provided <code>loop</code> or a default. It then delegates the core logic to <code>detail::request_text_once_async</code>, passing a lambda that invokes <code>call_completion_async&lt;Protocol&gt;</code> for the actual network request. The result is unwrapped using <code>detail::unwrap_caught_result</code>, and a cancellation of the inner <code>kota::task</code> is caught and re-raised as an <code>LLMError</code>. This design separates the retry and timeout logic (handled by <code>request_text_once_async</code>) from the single-shot completion call, while the template parameter <code>Protocol</code> allows the same flow to work with different LLM backends.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>performs an asynchronous LLM completion request via <code>call_completion_async</code></li><li>handles cancellation by setting a cancel error message</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>model</code></li><li>parameter <code>system_prompt</code></li><li>parameter <code>request</code></li><li>parameter <code>loop</code> (used to select event loop)</li><li>result of <code>detail::select_event_loop</code></li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value of type <code>kota::task&lt;std::string, clore::net::LLMError&gt;</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to initiate an asynchronous LLM request with cancellation support</li><li>used with an explicit event loop pointer or nullptr for default loop</li><li>invoked as part of a coroutine chain for LLM completion</li></ul><h3 id="clore-net-call-llm-async-1" tabindex="-1"><code>clore::net::call_llm_async</code> <a class="header-anchor" href="#clore-net-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:27</code></p><p>Definition: <code>network/client.cppm:156</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>The implementation of <code>clore::net::call_llm_async</code> begins by resolving the event loop via <code>detail::select_event_loop</code>, which returns a reference to either the provided pointer or a default loop. The coroutine then delegates all work to <code>detail::request_text_once_async</code>, a generic internal helper that orchestrates the actual LLM request life cycle. The first argument to that helper is a lambda that builds a <code>CompletionRequest</code> and forwards it to <code>call_completion_async&lt;Protocol&gt;</code>, ensuring that the completion path uses the same protocol and loop. The second, third, and fourth arguments are the <code>model</code>, <code>system_prompt</code>, and a <code>PromptRequest</code> struct containing the user <code>prompt</code> together with a <code>Markdown</code> output contract and no response format. After <code>request_text_once_async</code> completes, the function applies <code>.or_fail()</code> to unwrap the result or propagate any <code>LLMError</code>. The main dependency is <code>detail::select_event_loop</code>; the actual network interaction is abstracted into <code>call_completion_async</code> and the <code>request_text_once_async</code> machinery.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Initiates asynchronous network I/O to an LLM provider</li><li>Creates a coroutine task enabling suspension and later resumption</li><li>Allocates <code>PromptRequest</code>, <code>CompletionRequest</code>, and internal coroutine frame</li><li>May trigger rate-limit state updates or logging via called functions</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>Parameters <code>model</code>, <code>system_prompt</code>, <code>prompt</code></li><li>Global or function-static event loop state via <code>detail::select_event_loop</code></li><li>Probed capabilities cache via <code>get_probed_capabilities</code> (indirectly through <code>call_completion_async</code>)</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Event loop&#39;s pending task queue (via coroutine suspension)</li><li>Rate-limit counters or logs (indirectly via callees)</li><li>Promises and continuations in the coroutine pipeline</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>clore::net::call_structured_async</code></li><li>Used in high-level async LLM request flows for text generation</li><li>Invoked with template parameter <code>Protocol</code> to select the LLM protocol (e.g., <code>OpenAI</code>, Anthropic)</li></ul><h3 id="clore-net-call-structured-async" tabindex="-1"><code>clore::net::call_structured_async</code> <a class="header-anchor" href="#clore-net-call-structured-async" aria-label="Permalink to &quot;`clore::net::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:34</code></p><p>Definition: <code>network/client.cppm:177</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>The function template first retrieves a JSON schema describing the expected structured output by calling <code>clore::net::schema::response_format&lt;T&gt;()</code>. If the schema is unavailable, the coroutine immediately fails by yielding to <code>kota::fail</code>. Otherwise, a <code>clore::net::CompletionRequest</code> is constructed, containing the model identifier and a sequence of a system message and a user message, along with the obtained <code>response_format</code> and empty tool-related fields. The coroutine then delegates to <code>clore::net::call_completion_async&lt;Protocol&gt;</code>, passing the request and the event loop resolved via <code>clore::net::detail::select_event_loop</code>. After awaiting the completion call, the raw response string is parsed through <code>clore::net::protocol::parse_response_text&lt;T&gt;</code>. If parsing succeeds, the parsed value is returned; otherwise, the coroutine fails with the parse error. This flow ensures that the output strictly adheres to the type’s schema and that any failure in schema retrieval, API call, or response parsing is surfaced as a <code>clore::net::LLMError</code> via the coroutine’s error channel.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>allocates strings for request construction</li><li>performs asynchronous I/O via <code>call_completion_async</code></li><li>may propagate errors via <code>kota::fail</code></li></ul><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>model parameter</li><li><code>system_prompt</code> parameter</li><li>prompt parameter</li><li>loop parameter</li><li>global schema registry via <code>clore::net::schema::response_format&lt;T&gt;()</code></li></ul><h4 id="writes-to-3" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-3" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>internal <code>CompletionRequest</code> variable</li><li>response string from <code>call_completion_async</code></li><li>returned task containing parsed T value</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>invoked to obtain a structured typed response from an LLM</li><li>used in coroutine contexts requiring a <code>kota::task</code> for T</li><li>relies on schema registration for type T</li></ul><h3 id="clore-net-detail-select-event-loop" tabindex="-1"><code>clore::net::detail::select_event_loop</code> <a class="header-anchor" href="#clore-net-detail-select-event-loop" aria-label="Permalink to &quot;`clore::net::detail::select_event_loop`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:45</code></p><p>Definition: <code>network/client.cppm:45</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>Implementation: <a href="./functions/select-event-loop">Implementation</a></p><p>The function <code>clore::net::detail::select_event_loop</code> provides a single dispatch point for obtaining an active event loop reference. It first checks whether the incoming pointer <code>loop</code> is non‑null; if so, it dereferences and returns that loop directly. When <code>loop</code> is <code>nullptr</code>, the function falls back to <code>kota::event_loop::current()</code>, which must return a valid loop—this precondition is undefined if no event loop is active on the calling thread. The implementation thus relies on the runtime state of the <code>kota::event_loop</code> singleton and ensures the caller always receives a usable loop reference without further validation.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>loop</code></li><li>thread-local state accessed by <code>kota::event_loop::current()</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by async functions like <code>call_completion_async</code> and <code>call_llm_async</code> to resolve an optional event loop pointer to a valid reference before passing it to internal logic.</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>client</code> module (implemented in <code>network/client.cppm</code>) serves as the top-level orchestration layer for asynchronous interactions with large language models. It imports the <code>http</code> module for low‑level network dispatch, the <code>protocol</code> module for structured request/response types, and the <code>schema</code> module for generating <code>OpenAI</code>‑compliant JSON schemas, along with <code>support</code> for foundational utilities. Its public API consists of templated functions—<code>call_llm_async</code>, <code>call_completion_async</code>, and <code>call_structured_async</code>—each accepting a <code>kota::event_loop *</code> that defaults to an internally selected loop via the <code>detail::select_event_loop</code> helper. These functions manage the full lifecycle of an LLM request, from constructing payloads (e.g., from <code>system_prompt</code>, <code>model</code>, and <code>prompt</code> variables) to parsing responses and handling tool calls.</p><p>Internally, the module maintains state for active requests through variables such as <code>loop</code>, <code>active_loop</code>, <code>request_json</code>, <code>sanitized</code>, <code>tools_stripped</code>, and <code>caps</code>, which are exposed as public members for use by callers or inspectors. The <code>detail</code> namespace encapsulates the event‑loop selection logic, decoupling client code from the loop management details. This decomposition keeps the public interface clean while allowing the module to handle multiple concurrent asynchronous operations, rate‑limiting (via the <code>http</code> module), and structured‑output formatting transparently.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../http/">Module http</a></li><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../schema/">Module schema</a></li><li><a href="./../support/">Module support</a></li></ul>',70))])}const q=c(h,[["render",u]]);export{v as __pageData,q as default};
